-- Datos semilla exportados desde Factura Ferconsulting 2026.xlsm
begin;





-- Clientes activos de la hoja CLIENTES. Se conserva id para que coincida con data/clients.json.
select setval(pg_get_serial_sequence('public.clients', 'id'), greatest((select coalesce(max(id), 1) from public.clients), 1), true);

-- Servicios de la hoja SERVICIOS. Se conserva id para que coincida con data/services.json.
select setval(pg_get_serial_sequence('public.services', 'id'), greatest((select coalesce(max(id), 1) from public.services), 1), true);

commit;
